-- Patchnote 0.8.1 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.1', 'patch', '2026-05-10T00:00:00.000Z',
  'Seerr-compatible API, encryption-at-rest for credentials, qBittorrent 5.x support',
  'API compatible Seerr, chiffrement des identifiants au repos, support qBittorrent 5.x',
  '[{"type":"feat","titleEn":"Seerr-compatible API layer at /api/v1/*","titleFr":"Couche API compatible Seerr sous /api/v1/*","descEn":"Existing third-party tools that already speak Overseerr / Jellyseerr / Seerr can now point to Oscarr without waiting for a native integration. Tested against Homarr (dashboard widget) and Doplarr (Discord request bot). Each external app gets its own revokable API key from Admin → Access → API Keys; endpoints not yet implemented return a clean 501 Not Implemented so clients degrade gracefully. Compatibility is best-effort and limited to the endpoints third-party clients commonly call (status, auth/me, search, request, media, movie/tv, settings, user) — Oscarr is not affiliated with Overseerr, Jellyseerr or Seerr.","descFr":"Les outils tiers qui parlent déjà Overseerr / Jellyseerr / Seerr peuvent maintenant pointer sur Oscarr sans attendre une intégration native. Testé contre Homarr (widget dashboard) et Doplarr (bot Discord de requêtes). Chaque app externe a sa propre clé API révocable depuis Admin → Access → API Keys ; les endpoints non encore implémentés retournent un 501 Not Implemented propre pour que les clients dégradent gracieusement. Compatibilité best-effort limitée aux endpoints courants (status, auth/me, search, request, media, movie/tv, settings, user) — Oscarr n''est pas affilié à Overseerr, Jellyseerr ou Seerr."},{"type":"feat","titleEn":"Per-app API keys with revocation","titleFr":"Clés API par application avec révocation","descEn":"Generate one named API key per third-party integration from Admin → Access → API Keys. Keys are sha256-hashed at rest, only the prefix is kept for display, and revocation is a one-click soft-delete that keeps the audit trail (last used, created, revoked timestamps). The legacy AppSettings.apiKey global key still exists for /webhooks and /health — the new keys are scoped to the admin user that generated them.","descFr":"Génère une clé API nommée par intégration tierce depuis Admin → Access → Clés API. Les clés sont sha256-hashées au repos, seul le préfixe est conservé pour affichage, et la révocation est un soft-delete en un clic qui préserve l''historique (dernière utilisation, création, révocation). La clé globale AppSettings.apiKey continue d''exister pour /webhooks et /health — les nouvelles clés sont scopées à l''utilisateur admin qui les a générées."},{"type":"feat","titleEn":"AES-256-GCM encryption at rest for service credentials","titleFr":"Chiffrement AES-256-GCM au repos pour les identifiants des services","descEn":"Stored credentials in Service.config (Radarr / Sonarr / Plex / qBittorrent / Jellyfin / Tautulli / Jackett — API keys, tokens, passwords) are now encrypted at rest with AES-256-GCM and a master key derived through HKDF-SHA256 from a new mandatory OSCARR_SECRET_KEY environment variable. If the variable is missing or malformed, the process prints a friendly fatal message with a freshly-generated key the operator can copy/paste. A floating banner in the admin panel prompts existing instances to re-save each service so their credentials switch from plaintext to encrypted (re-saving without changing the value is enough — the merge logic preserves and re-encrypts the stored secret).","descFr":"Les identifiants stockés dans Service.config (Radarr / Sonarr / Plex / qBittorrent / Jellyfin / Tautulli / Jackett — clés API, tokens, mots de passe) sont maintenant chiffrés au repos en AES-256-GCM avec une clé maître dérivée par HKDF-SHA256 depuis la nouvelle variable d''environnement obligatoire OSCARR_SECRET_KEY. Si elle manque ou est invalide, le processus affiche un message d''erreur amical avec une clé fraîchement générée à copier-coller. Un bandeau flottant dans le panel admin invite les instances existantes à re-sauvegarder chaque service pour que ses identifiants passent de plaintext à chiffré (re-sauvegarder sans changer la valeur suffit — la logique de merge conserve et re-chiffre le secret stocké)."},{"type":"feat","titleEn":"Secure password reveal/copy flow for stored service credentials","titleFr":"Affichage et copie sécurisés des identifiants stockés","descEn":"Replaces the legacy globalThis.prompt() flow with an in-app modal — focus-trapped, accessible, dismissable. Reveal shows the value for 8 seconds then auto-remasks (limits the shoulder-surf window). Copy fetches the value server-side and writes it to the clipboard without ever displaying it on screen.","descFr":"Remplace le flux globalThis.prompt() historique par un modal in-app — focus-trapped, accessible, fermable. La révélation affiche la valeur pendant 8 secondes puis re-masque automatiquement (limite la fenêtre d''observation). La copie récupère la valeur côté serveur et l''écrit dans le presse-papier sans jamais l''afficher à l''écran."},{"type":"feat","titleEn":"qBittorrent 5.x compatibility (API key auth)","titleFr":"Compatibilité qBittorrent 5.x (auth par clé API)","descEn":"qBittorrent 5.x renamed the WebAPI session cookie (SID → SID<port>) and the pause/resume endpoints (/torrents/pause → /torrents/stop). The connector now switches to the new API key authentication added in 5.x — admins paste a key from qBit Settings → WebUI → Authentication → Generate API key, and the username/password fields disappear. The qBittorrent Manager plugin gained the same change in v0.2.0 along with stopped*-state aliases so paused torrents land in the right tab in both 4.x and 5.x.","descFr":"qBittorrent 5.x a renommé le cookie de session WebAPI (SID → SID<port>) et les endpoints pause/resume (/torrents/pause → /torrents/stop). Le connecteur passe désormais sur l''authentification par clé API ajoutée en 5.x — les admins collent une clé depuis qBit Settings → WebUI → Authentication → Generate API key, et les champs username/mot de passe disparaissent. Le plugin qBittorrent Manager a reçu le même changement en v0.2.0 avec les alias d''état stopped* pour que les torrents en pause atterrissent dans le bon onglet en 4.x et 5.x."},{"type":"feat","titleEn":"TMDB trending backdrop on the login page","titleFr":"Backdrop TMDB en tendance sur la page de login","descEn":"The login page now picks a random backdrop from the top 10 trending titles at mount and locks it for the lifetime of the page. No rotation, no fade — a hard refresh rolls a new one. Reuses the existing /api/tmdb/trending endpoint (now public, since trending is public TMDB data anyway).","descFr":"La page de login choisit maintenant un backdrop aléatoire parmi les 10 titres les plus tendances au montage et le verrouille pour la durée de la page. Pas de rotation, pas de fondu — un rafraîchissement complet en tire un nouveau. Réutilise l''endpoint /api/tmdb/trending existant (maintenant public, puisque les tendances sont des données TMDB publiques de toute façon)."},{"type":"feat","titleEn":"Searchable Discover with filters + reusable ConfirmModal","titleFr":"Discover plugins avec recherche/filtres + ConfirmModal réutilisable","descEn":"The Plugins → Discover tab gains a search input (matches name, description, author, category and tags), a Hide installed toggle (default on) and a Nouveau / New filter that surfaces plugins released within the last 14 days. The grid splits into Nouveautés and Tous les plugins sections so card titles stay readable even when long. Destructive actions in the admin (revoke API key today, more tomorrow) now use a reusable ConfirmModal component instead of the native confirm() dialog.","descFr":"L''onglet Plugins → Discover gagne une barre de recherche (matche nom, description, auteur, catégorie et tags), un toggle Masquer les installés (par défaut activé) et un filtre Nouveau qui surface les plugins publiés dans les 14 derniers jours. La grille se divise en Nouveautés et Tous les plugins pour garder les titres lisibles même quand longs. Les actions destructives dans l''admin (révoquer une clé API pour l''instant, d''autres ensuite) utilisent maintenant un composant ConfirmModal réutilisable au lieu du confirm() natif."},{"type":"refactor","titleEn":"Drop *arr tag-based request sync","titleFr":"Suppression du sync des demandes basé sur les tags *arr","descEn":"The cron job that walked Radarr/Sonarr tags every 5 minutes to back-fill request rows was removed — it depended on a brittle precondition (the upstream tool must be configured to write per-user tags) and silently mis-attributed requests when that precondition wasn''t met. The legacy CronJob row is dropped via migration. A proper Seerr/Overseerr import flow is tracked under issue #192.","descFr":"Le cron qui parcourait les tags Radarr/Sonarr toutes les 5 minutes pour back-fill les demandes a été supprimé — il dépendait d''une précondition fragile (l''outil upstream doit être configuré pour écrire des tags par utilisateur) et attribuait silencieusement les demandes au mauvais utilisateur quand ce n''était pas le cas. La row CronJob historique est supprimée via migration. Un flow d''import Seerr/Overseerr propre est tracké via l''issue #192."},{"type":"fix","titleEn":"Bump better-sqlite3 to 12.9 for Node 24+ support","titleFr":"Bump better-sqlite3 vers 12.9 pour le support Node 24+","descEn":"better-sqlite3 11.10 only shipped prebuilt binaries up to Node 22 and failed to compile from source against Node 24+ (v8 API breaking changes). 12.9 supports the 20.x → 25.x range and resolves the NODE_MODULE_VERSION mismatch admins running Node 24+ were seeing on the plugin storage layer. Prisma''s own bundled libquery_engine is unaffected.","descFr":"better-sqlite3 11.10 n''embarquait des binaires précompilés que jusqu''à Node 22 et échouait à compiler depuis les sources contre Node 24+ (changements cassants de l''API v8). La 12.9 supporte la plage 20.x → 25.x et résout le mismatch NODE_MODULE_VERSION que les admins en Node 24+ voyaient sur la couche de stockage des plugins. Le libquery_engine embarqué de Prisma n''est pas affecté."},{"type":"other","titleEn":"Slim README + docs/installation.md","titleFr":"README allégé + docs/installation.md","descEn":"The top-level README was 280 lines of mixed-density content (vision, install, manifest examples, project tree). Slimmed to the elevator pitch (Core capabilities, Seerr-compat API, Featured plugins) plus the Docker quick-start. The bare-metal install, full env-var reference and project structure walkthrough moved to the new docs/installation.md.","descFr":"Le README de premier niveau faisait 280 lignes de contenu de densité mixte (vision, install, exemples de manifest, arbre projet). Allégé au pitch (Core capabilities, API Seerr-compat, plugins en vedette) plus le quick-start Docker. L''install bare-metal, la référence complète des variables d''env et le tour de la structure projet ont été déplacés dans le nouveau docs/installation.md."}]'
) ON CONFLICT ("version") DO NOTHING;
